import React, { useMemo } from 'react';
import { useI18n } from '../i18n/I18nContext';

/* ── Floating bubble background ────────────────────── */
const BUBBLE_COUNT = 14;
const bubbleKeyframes = `
@keyframes floatBubble {
  0%   { transform: translateY(0)   scale(1);     opacity: 0; }
  10%  { opacity: 1; }
  90%  { opacity: 1; }
  100% { transform: translateY(-110vh) scale(0.4); opacity: 0; }
}`;

function FloatingBubbles() {
    const bubbles = useMemo(() => {
        const palette = [
            'rgba(59,130,246,0.12)',   // blue
            'rgba(139,92,246,0.12)',   // purple
            'rgba(16,185,129,0.10)',   // emerald
            'rgba(236,72,153,0.10)',   // pink
            'rgba(251,191,36,0.08)',   // amber
        ];
        return Array.from({ length: BUBBLE_COUNT }, (_, i) => {
            const size = 18 + Math.random() * 60;
            return {
                key: i,
                size,
                left: `${Math.random() * 100}%`,
                duration: `${12 + Math.random() * 18}s`,
                delay: `${-Math.random() * 20}s`,
                color: palette[i % palette.length],
            };
        });
    }, []);

    return (
        <>
            <style>{bubbleKeyframes}</style>
            <div className="absolute inset-0 overflow-hidden pointer-events-none" aria-hidden="true">
                {bubbles.map(b => (
                    <div
                        key={b.key}
                        style={{
                            position: 'absolute',
                            bottom: '-20%',
                            left: b.left,
                            width: b.size,
                            height: b.size,
                            borderRadius: '50%',
                            background: b.color,
                            animation: `floatBubble ${b.duration} ${b.delay} infinite ease-in`,
                        }}
                    />
                ))}
            </div>
        </>
    );
}

const LoginView = ({
    loginView,
    gameId,
    roomPassword,
    playerName,
    setLoginView,
    setGameId,
    setRoomPassword,
    setPlayerName,
    createPassword,
    setCreatePassword,
    joinRoomCode,
    setJoinRoomCode,
    joinRoomPin,
    setJoinRoomPin,
    availableRooms,
    loadingRooms,
    fetchRooms,
    selectedRoom,
    setSelectedRoom,
    handleJoinGame,
    handleFinalJoin,
    pendingJoin,
    setPendingJoin,
    setMessage,
    setMessageType,
    SOCKET_URL,
    setURLRoom,
    gameTimeLimit,
    setGameTimeLimit,
    roomNotFound,
}) => {
    const { t } = useI18n();

    // Shared password-check helper to avoid duplication
    const checkPassword = async (roomId, pin) => {
        const ac = new AbortController();
        try {
            const res = await fetch(`${SOCKET_URL}/rooms/${roomId}/check-password`, {
                method: 'POST', headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ password: pin }),
                signal: ac.signal,
            });
            const data = await res.json();
            if (!data.valid) {
                setMessage(`❌ ${data.error || t('login.incorrectPin')}`);
                setMessageType('error');
                return false;
            }
            return true;
        } catch (err) {
            if (err.name !== 'AbortError') {
                setMessage(t('login.failedValidate'));
                setMessageType('error');
            }
            return false;
        }
    };

    return (
        <div className="relative min-h-full">
            <FloatingBubbles />
        <div className="max-w-md mx-auto space-y-4 pt-4 relative z-10">
            <div className="text-center space-y-2">
                <div className="relative inline-block">
                    <div className="text-6xl sm:text-7xl animate-bounce" style={{ animationDuration: '2s' }}>⚓</div>
                    <div className="absolute -top-1 -right-3 bg-yellow-500 text-[0.5rem] font-black text-slate-900 px-1.5 py-0.5 rounded-full shadow-md">v2</div>
                </div>
                <h2 className="text-3xl sm:text-4xl font-black bg-gradient-to-r from-blue-400 via-purple-400 to-pink-400 bg-clip-text text-transparent">{t('login.title')}</h2>
                <div className="flex items-center justify-center gap-2 text-slate-400 text-sm">
                    <span className="w-8 h-px bg-slate-600" />
                    <span>{t('login.subtitle')}</span>
                    <span className="w-8 h-px bg-slate-600" />
                </div>
                <p className="text-[0.6rem] text-slate-500 mt-1">Created by Adrians Bergmanis</p>
            </div>

            {/* MENU VIEW */}
            {loginView === 'menu' && !gameId && (
                <div className="space-y-3">
                    <button
                        onClick={() => setLoginView('create')}
                        className="group w-full py-4 bg-gradient-to-r from-emerald-500 to-green-500 hover:from-emerald-400 hover:to-green-400 text-white font-bold rounded-2xl transition-all hover:scale-[1.02] shadow-lg shadow-emerald-900/30 text-base flex items-center justify-center gap-2"
                    >
                        <span className="text-xl group-hover:rotate-12 transition-transform">⚔️</span> {t('login.createGame')}
                    </button>
                    <button
                        onClick={() => setLoginView('join')}
                        className="group w-full py-4 bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-500 hover:to-purple-500 text-white font-bold rounded-2xl transition-all hover:scale-[1.02] shadow-lg shadow-purple-900/30 text-base flex items-center justify-center gap-2"
                    >
                        <span className="text-xl group-hover:translate-x-1 transition-transform">⛵</span> {t('login.joinGame')}
                    </button>
                </div>
            )}

            {/* URL JOIN VIEW */}
            {(gameId && loginView !== 'create' && loginView !== 'enterName') && (
                roomNotFound ? (
                    <div className="space-y-4">
                        <div className="bg-red-900/30 border border-red-500/50 rounded-2xl p-5 text-center space-y-2">
                            <div className="text-4xl">🚫</div>
                            <p className="text-red-300 font-bold text-lg">{t('login.roomNotFound')}</p>
                            <p className="text-slate-400 text-sm">
                                <span className="font-mono font-bold text-yellow-300">{gameId}</span> {t('login.roomNotFoundDesc')}
                            </p>
                        </div>
                        <button
                            onClick={() => { setURLRoom(null); setGameId(''); setLoginView('menu'); }}
                            className="w-full py-3 bg-slate-700 hover:bg-slate-600 text-white font-bold rounded-2xl transition-all"
                        >
                            {t('login.backToMenu')}
                        </button>
                    </div>
                ) : (
                    <div className="space-y-4">
                    <div className="bg-blue-900/30 border border-blue-500/50 rounded-2xl p-4 text-center">
                        <p className="text-blue-300 text-sm mb-1">{t('login.invitedToJoin')}</p>
                        <p className="text-2xl font-black font-mono text-yellow-300 tracking-widest">{gameId}</p>
                        {roomPassword && <p className="text-xs text-green-400 mt-2">🔒 PIN: <span className="font-mono font-bold">{roomPassword}</span></p>}
                    </div>
                    {!roomPassword && (
                        <div className="bg-slate-800/80 rounded-2xl p-4 border border-slate-700 space-y-2">
                            <label className="block text-xs font-semibold text-slate-400 uppercase tracking-widest">{t('login.pinIfRequired')}</label>
                            <input
                                type="text"
                                inputMode="numeric"
                                value={roomPassword || ''}
                                onChange={e => setRoomPassword(e.target.value.replace(/\D/g, '').slice(0, 3))}
                                maxLength={3}
                                placeholder="123"
                                className="w-full px-4 py-2.5 bg-slate-700 border border-slate-600 rounded-xl text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-blue-500 font-mono tracking-[0.5em] text-center text-lg"
                            />
                        </div>
                    )}
                    <button
                        onClick={() => {
                            setPendingJoin({ roomId: gameId, password: roomPassword || null });
                            setLoginView('enterName');
                        }}
                        className="w-full py-3.5 bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-500 hover:to-purple-500 text-white font-bold rounded-2xl transition-all hover:scale-[1.02] shadow-lg text-base"
                    >
                        {t('login.joinGameBtn')}
                    </button>
                    <button
                        onClick={() => {
                            setPendingJoin({ roomId: gameId, password: roomPassword || null, isSpectating: true });
                            setLoginView('enterName');
                        }}
                        className="w-full py-3.5 border border-purple-500/50 text-purple-300 hover:bg-purple-500/20 font-bold rounded-2xl transition-all hover:scale-[1.02] text-base"
                    >
                        {t('login.spectateBtn')}
                    </button>
                    <button
                        onClick={() => { setGameId(''); setRoomPassword(''); setURLRoom(null); setLoginView('menu'); }}
                        className="w-full py-2.5 bg-slate-700 hover:bg-slate-600 text-slate-300 font-semibold rounded-xl transition text-sm"
                    >
                        {t('login.backToMenu')}
                    </button>
                    </div>
                )
            )}

            {/* CREATE VIEW */}
            {loginView === 'create' && !gameId && (
                <div className="space-y-4 animate-fade-in">
                    <div className="bg-gradient-to-br from-slate-800/90 to-slate-900/90 rounded-2xl p-5 border border-emerald-500/20 space-y-4 shadow-lg shadow-emerald-900/10">
                        <h3 className="text-lg font-bold text-white flex items-center gap-2">⚔️ {t('login.createNewGame')}</h3>
                        <div className="space-y-2">
                            <label className="block text-xs font-semibold text-slate-400 uppercase tracking-widest">{t('login.pinCodeOptional')}</label>
                            <input
                                type="text"
                                inputMode="numeric"
                                value={createPassword}
                                onChange={e => setCreatePassword(e.target.value.replace(/\D/g, '').slice(0, 3))}
                                maxLength={3}
                                placeholder="123"
                                className="w-full px-4 py-3 bg-slate-700/80 border border-slate-600 rounded-xl text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-emerald-500/50 font-mono tracking-[0.5em] text-center text-2xl transition-all"
                            />
                            <p className="text-[0.65rem] text-slate-500">{t('login.pinHint')}</p>
                        </div>

                        <div className="space-y-2 pt-2 border-t border-slate-700/50">
                            <label className="block text-xs font-semibold text-slate-400 uppercase tracking-widest">{t('login.timePerPlayer')}</label>
                            <div className="flex items-center gap-3">
                                <input
                                    type="range"
                                    min={2}
                                    max={10}
                                    value={Math.round((gameTimeLimit || 300) / 60)}
                                    onChange={e => setGameTimeLimit(parseInt(e.target.value) * 60)}
                                    className="flex-1 accent-emerald-500"
                                />
                                <span className="text-lg font-mono font-bold text-emerald-300 w-16 text-center bg-emerald-500/10 rounded-lg py-1">{Math.round((gameTimeLimit || 300) / 60)} {t('login.min')}</span>
                            </div>
                            <p className="text-[0.65rem] text-slate-500">{t('login.timeHint')}</p>
                        </div>

                        <button
                            onClick={() => {
                                if (createPassword && createPassword.length !== 3) { setMessage(t('login.pinError')); setMessageType('error'); return; }
                                const id = Math.random().toString(36).slice(2, 8).toUpperCase();
                                setPendingJoin({ roomId: id, password: createPassword || null, isCreating: true, timeLimit: gameTimeLimit || 300 });
                                setLoginView('enterName');
                            }}
                            className="w-full py-3.5 bg-gradient-to-r from-emerald-500 to-green-500 hover:from-emerald-400 hover:to-green-400 text-white font-bold rounded-2xl transition-all hover:scale-[1.02] shadow-lg shadow-emerald-900/20 text-base"
                        >
                            {t('login.createGameBtn')}
                        </button>
                    </div>
                    <button
                        onClick={() => setLoginView('menu')}
                        className="w-full py-2.5 bg-slate-700 hover:bg-slate-600 text-slate-300 font-semibold rounded-xl transition text-sm"
                    >
                        {t('login.backToMenu')}
                    </button>
                </div>
            )}

            {/* JOIN VIEW */}
            {loginView === 'join' && !gameId && (
                <div className="space-y-4">
                    <div className="bg-slate-800/80 rounded-2xl p-4 border border-slate-700 space-y-3">
                        <label className="block text-xs font-semibold text-slate-400 uppercase tracking-widest">{t('login.roomCode')}</label>
                        <input
                            type="text"
                            value={joinRoomCode}
                            onChange={e => setJoinRoomCode(e.target.value.toUpperCase().replace(/[^A-Z0-9]/g, ''))}
                            maxLength={10}
                            placeholder={t('login.roomCodePlaceholder')}
                            className="w-full px-4 py-3 bg-slate-700 border border-slate-600 rounded-xl text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-blue-500 font-mono tracking-[0.3em] text-center text-xl"
                        />
                        <div className="space-y-2">
                            <label className="block text-xs font-semibold text-slate-400 uppercase tracking-widest">{t('login.pinIfRequired')}</label>
                            <input
                                type="text"
                                inputMode="numeric"
                                value={joinRoomPin}
                                onChange={e => setJoinRoomPin(e.target.value.replace(/\D/g, '').slice(0, 3))}
                                maxLength={3}
                                placeholder="123"
                                className="w-full px-4 py-2.5 bg-slate-700 border border-slate-600 rounded-xl text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-blue-500 font-mono tracking-[0.5em] text-center text-lg"
                            />
                        </div>
                        <div className="flex gap-2">
                            <button
                                onClick={handleJoinGame}
                                disabled={!joinRoomCode.trim()}
                                className="flex-1 py-3 bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-500 hover:to-purple-500 disabled:opacity-50 disabled:cursor-not-allowed text-white font-bold rounded-xl transition-all hover:scale-[1.02]"
                            >
                                {t('login.joinAsPlayer')}
                            </button>
                            <button
                                onClick={() => {
                                    if (!joinRoomCode.trim()) return;
                                    setPendingJoin({ roomId: joinRoomCode.trim(), password: joinRoomPin || null, isSpectating: true });
                                    setLoginView('enterName');
                                }}
                                disabled={!joinRoomCode.trim()}
                                className="flex-1 py-3 border border-purple-500/50 text-purple-300 hover:bg-purple-500/20 disabled:opacity-50 disabled:cursor-not-allowed font-bold rounded-xl transition-all hover:scale-[1.02]"
                            >
                                {t('login.spectateBtn')}
                            </button>
                        </div>
                    </div>

                    <div className="bg-slate-800/80 rounded-2xl p-4 border border-slate-700 space-y-3">
                        <div className="flex items-center justify-between">
                            <label className="text-xs font-semibold text-slate-400 uppercase tracking-widest">{t('login.openRooms')}</label>
                            <button
                                onClick={fetchRooms}
                                disabled={loadingRooms}
                                className="text-xs text-blue-400 hover:text-blue-300 disabled:opacity-50"
                            >
                                {loadingRooms ? '⏳' : '🔄'} {t('login.refresh')}
                            </button>
                        </div>

                        {loadingRooms ? (
                            <div className="text-center py-4 text-slate-500 text-sm">{t('login.loadingRooms')}</div>
                        ) : availableRooms.length === 0 ? (
                            <div className="text-center py-4 text-slate-500 text-sm">
                                {t('login.noRooms')}<br />
                                <span className="text-xs">{t('login.noRoomsHint')}</span>
                            </div>
                        ) : (
                            <div className="space-y-2 max-h-48 overflow-y-auto">
                                {availableRooms.map(room => (
                                    <div key={room.roomId} className="bg-slate-700/50 rounded-xl overflow-hidden">
                                        <button
                                            onClick={() => {
                                                setSelectedRoom(selectedRoom === room.roomId ? null : room.roomId);
                                                setJoinRoomPin('');
                                            }}
                                            className="w-full flex items-center justify-between p-3 hover:bg-slate-600/50 transition text-left"
                                        >
                                            <div>
                                                <span className="font-mono font-bold text-yellow-300 tracking-wider">{room.roomId}</span>
                                                <span className="text-slate-400 text-sm ml-2">{t('login.by')}{room.hostName}</span>
                                            </div>
                                            <div className="flex items-center gap-2">
                                                {room.hasPassword ? (
                                                    <span className="text-xs bg-orange-500/20 text-orange-300 px-2 py-0.5 rounded-full">{t('login.pinLocked')}</span>
                                                ) : room.state !== 'WAITING_FOR_PLAYERS' ? (
                                                    <span className="text-xs bg-purple-500/20 text-purple-300 px-2 py-0.5 rounded-full">{t('login.spectate')}</span>
                                                ) : (
                                                    <span className="text-xs bg-green-500/20 text-green-300 px-2 py-0.5 rounded-full">{t('login.open')}</span>
                                                )}
                                            </div>
                                        </button>
                                        {selectedRoom === room.roomId && (
                                            <div className="px-3 pb-3 pt-1 bg-slate-600/30 space-y-2">
                                                <div className="flex items-center gap-2 text-xs text-slate-400 flex-wrap">
                                                    <span>👥 {room.playerCount}/2</span>
                                                    {room.timeLimit && <span>⏱ {Math.round(room.timeLimit / 60)} {t('login.min')}</span>}
                                                    {room.state !== 'WAITING_FOR_PLAYERS'
                                                        ? <span className="text-purple-300">{t('login.inProgress')}</span>
                                                        : <span className="text-green-300">{t('login.open')}</span>}
                                                </div>
                                                {room.hasPassword && (
                                                    <input
                                                        type="text"
                                                        inputMode="numeric"
                                                        value={joinRoomPin}
                                                        onChange={e => setJoinRoomPin(e.target.value.replace(/\D/g, '').slice(0, 3))}
                                                        maxLength={3}
                                                        placeholder={t('login.3digitPin')}
                                                        autoFocus
                                                        className="w-full px-3 py-2 bg-slate-700 border border-slate-600 rounded-lg text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-blue-500 font-mono tracking-[0.3em] text-center"
                                                    />
                                                )}
                                                <div className="flex gap-2">
                                                    <button
                                                        onClick={async () => {
                                                            if (room.hasPassword) {
                                                                if (joinRoomPin.length !== 3) { setMessage(t('login.pinError3')); setMessageType('error'); return; }
                                                                const valid = await checkPassword(room.roomId, joinRoomPin);
                                                                if (!valid) return;
                                                            }
                                                            setPendingJoin({ roomId: room.roomId, password: room.hasPassword ? joinRoomPin : null });
                                                            setLoginView('enterName');
                                                        }}
                                                        disabled={(room.hasPassword && joinRoomPin.length !== 3) || room.playerCount >= 2 || room.state !== 'WAITING_FOR_PLAYERS'}
                                                        className="flex-1 py-2 bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-500 hover:to-purple-500 disabled:opacity-50 disabled:cursor-not-allowed text-white font-bold rounded-lg transition text-sm"
                                                    >
                                                        {room.playerCount >= 2 ? t('login.roomFull') : t('login.joinAsPlayer')}
                                                    </button>
                                                    <button
                                                        onClick={async () => {
                                                            if (room.hasPassword) {
                                                                if (joinRoomPin.length !== 3) { setMessage(t('login.pinError3')); setMessageType('error'); return; }
                                                                const valid = await checkPassword(room.roomId, joinRoomPin);
                                                                if (!valid) return;
                                                            }
                                                            setPendingJoin({ roomId: room.roomId, password: room.hasPassword ? joinRoomPin : null, isSpectating: true });
                                                            setLoginView('enterName');
                                                        }}
                                                        disabled={room.hasPassword && joinRoomPin.length !== 3}
                                                        className="flex-1 py-2 border border-purple-500/50 text-purple-300 hover:bg-purple-500/20 disabled:opacity-50 disabled:cursor-not-allowed font-bold rounded-lg transition text-sm"
                                                    >
                                                        {t('login.spectateBtn')}
                                                    </button>
                                                </div>
                                            </div>
                                        )}
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>

                    <button
                        onClick={() => { setLoginView('menu'); setJoinRoomCode(''); setJoinRoomPin(''); }}
                        className="w-full py-2.5 bg-slate-700 hover:bg-slate-600 text-slate-300 font-semibold rounded-xl transition text-sm"
                    >
                        {t('login.backToMenu')}
                    </button>
                </div>
            )}

            {/* ENTER NAME VIEW */}
            {loginView === 'enterName' && pendingJoin && (
                <div className="space-y-4">
                    <div className="bg-blue-900/30 border border-blue-500/50 rounded-2xl p-4 text-center">
                        <p className="text-blue-300 text-sm mb-1">{pendingJoin.isCreating ? t('login.creatingRoom') : pendingJoin.isSpectating ? t('login.spectatingRoom') : t('login.joiningRoom')}</p>
                        <p className="text-2xl font-black font-mono text-yellow-300 tracking-widest">{pendingJoin.roomId}</p>
                        {pendingJoin.password && <p className="text-xs text-green-400 mt-2">🔒 PIN: <span className="font-mono font-bold">{pendingJoin.password}</span></p>}
                    </div>
                    <div className="bg-slate-800/80 rounded-2xl p-4 border border-slate-700">
                        <label className="block text-xs font-semibold text-slate-400 uppercase tracking-widest mb-2">{t('login.yourName')}</label>
                        <input
                            type="text"
                            value={playerName}
                            onChange={e => setPlayerName(e.target.value)}
                            onKeyDown={e => {
                                if (e.key === 'Enter' && playerName.trim()) {
                                    handleFinalJoin();
                                }
                            }}
                            maxLength={50}
                            placeholder={t('login.namePlaceholder')}
                            autoFocus
                            className="w-full px-4 py-3 bg-slate-700 border border-slate-600 rounded-xl text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-blue-500"
                        />
                    </div>
                    <button
                        onClick={handleFinalJoin}
                        disabled={!playerName.trim()}
                        className="w-full py-3.5 bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-500 hover:to-purple-500 disabled:opacity-50 disabled:cursor-not-allowed text-white font-bold rounded-2xl transition-all hover:scale-[1.02] shadow-lg text-base"
                    >
                        {pendingJoin.isCreating ? t('login.createAndJoin') : pendingJoin.isSpectating ? t('login.watchGame') : t('login.joinGameBtn')}
                    </button>
                    <button
                        onClick={() => {
                            setLoginView(pendingJoin.isCreating ? 'create' : (gameId ? 'menu' : 'join'));
                            setPendingJoin(null);
                            if (gameId) { setGameId(''); setRoomPassword(''); setURLRoom(null); }
                        }}
                        className="w-full py-2.5 bg-slate-700 hover:bg-slate-600 text-slate-300 font-semibold rounded-xl transition text-sm"
                    >
                        {t('login.back')}
                    </button>
                </div>
            )}
        </div>
        </div>
    );
};

export default LoginView;
